using Microsoft.AspNetCore.Http.Features;

var builder = WebApplication.CreateBuilder(args);

// Raise the max request body size (default is ~30 MB)
builder.WebHost.ConfigureKestrel(o => o.Limits.MaxRequestBodySize = 50 * 1024 * 1024);

var app = builder.Build();

app.MapPost("/upload", async (IFormFileCollection files, HttpRequest request) =>
{
    // Read the description field from the same multipart form
    var description = request.Form["description"].ToString();

    if (files.Count == 0)
        return Results.BadRequest("No files uploaded.");

    var saved = new List<string>();

    foreach (var file in files)
    {
        if (!file.ContentType.StartsWith("image/"))
            return Results.BadRequest($"'{file.FileName}' is not an image.");

        var path = Path.Combine("uploads", file.FileName);
        Directory.CreateDirectory("uploads");

        await using var stream = File.Create(path);
        await file.CopyToAsync(stream);
        saved.Add(file.FileName);
    }

    return Results.Ok(new { description, uploadedFiles = saved });
})
.DisableAntiforgery()                          // needed for minimal APIs accepting forms
.WithRequestFormLimits(multipartBodyLengthLimit: 50 * 1024 * 1024);  // per-endpoint form limit

app.Run();
```

**Key points:**

- `IFormFileCollection` binds all files from any `<input type="file" multiple name="files">`.
- `WithRequestFormLimits` raises the per-endpoint multipart limit to 50 MB.
- `ConfigureKestrel` raises the server-wide request body cap to match.
- `.DisableAntiforgery()` is required in .NET 8 minimal APIs that accept form data without an antiforgery token.
- The `description` field is read from `request.Form` since it's a plain text field in the same form.

**Example `curl` call:**

```bash
curl -X POST http://localhost:5000/upload \
  -F "files=@photo1.jpg" \
  -F "files=@photo2.png" \
  -F "description=Vacation photos"
```
